################################################################################
## Form generated by hand to match the Designer-output pattern (no .ui file).
##
## 发票识别 Tab 的纯布局代码 —— 与 batch_mkdir/pdf/rename/replace 的
## generated/ui_*_dialog.py 风格一致:一个 Ui_* 类,setupUi(self, Widget) 构建控件树。
## 业务逻辑(信号连接/解析/导出)留在 dialogs/invoice_tab.py 的 InvoiceTab。
##
## WARNING! 若日后用 Qt Designer 重新生成,本文件会被覆盖。
################################################################################

from PySide6.QtWidgets import (
    QButtonGroup,
    QComboBox,
    QHBoxLayout,
    QHeaderView,
    QLabel,
    QLineEdit,
    QListWidget,
    QPushButton,
    QRadioButton,
    QTableWidget,
    QVBoxLayout,
    QWidget,
)

# 表格列头(与 invoice 业务字段一一对应;放此处供 setupUi 与测试共用)
HEADERS = [
    "发票号码",
    "发票类型",
    "开票日期",
    "销售方",
    "购买方",
    "价税合计",
    "来源",
    "解析方式",
]


class Ui_InvoiceDialog:
    """发票识别 Tab 的 UI 构建器(setupUi 模式,与其他 Tab 一致)。"""

    def setupUi(self, InvoiceDialog: QWidget) -> None:
        if not InvoiceDialog.objectName():
            InvoiceDialog.setObjectName("InvoiceDialog")

        layout = QVBoxLayout(InvoiceDialog)
        layout.setObjectName("verticalLayout_main")

        # ---- 文件选择行 ----
        file_row = QHBoxLayout()
        file_row.setObjectName("horizontalLayout_files")

        self.btn_add_files = QPushButton("添加文件", InvoiceDialog)
        self.btn_add_files.setObjectName("btn_add_files")
        file_row.addWidget(self.btn_add_files)

        self.btn_add_folder = QPushButton("添加文件夹", InvoiceDialog)
        self.btn_add_folder.setObjectName("btn_add_folder")
        file_row.addWidget(self.btn_add_folder)

        self.btn_clear = QPushButton("清空", InvoiceDialog)
        self.btn_clear.setObjectName("btn_clear")
        file_row.addWidget(self.btn_clear)

        file_row.addStretch(1)
        layout.addLayout(file_row)

        self.list_files = QListWidget(InvoiceDialog)
        self.list_files.setObjectName("list_files")
        layout.addWidget(self.list_files)

        # ---- 选项行(格式 / 去重 / 输出目录) ----
        opt_row = QHBoxLayout()
        opt_row.setObjectName("horizontalLayout_options")

        opt_row.addWidget(QLabel("格式:", InvoiceDialog))

        self.rb_excel = QRadioButton("Excel", InvoiceDialog)
        self.rb_excel.setObjectName("rb_excel")
        self.rb_excel.setChecked(True)
        opt_row.addWidget(self.rb_excel)

        self.rb_json = QRadioButton("JSON", InvoiceDialog)
        self.rb_json.setObjectName("rb_json")
        opt_row.addWidget(self.rb_json)

        self.rb_both = QRadioButton("两者", InvoiceDialog)
        self.rb_both.setObjectName("rb_both")
        opt_row.addWidget(self.rb_both)

        # 单选按钮互斥:QButtonGroup(默认 autoExclusive=True 仅在同父控件内生效,
        # 这里显式分组确保语义清晰,与其他 Tab 的 QButtonGroup 用法一致)
        self.fmt_group = QButtonGroup(InvoiceDialog)
        for rb in (self.rb_excel, self.rb_json, self.rb_both):
            self.fmt_group.addButton(rb)

        opt_row.addWidget(QLabel("去重:", InvoiceDialog))

        self.cmb_dedupe = QComboBox(InvoiceDialog)
        self.cmb_dedupe.setObjectName("cmb_dedupe")
        self.cmb_dedupe.addItems(["keep_all(不处理)", "dedupe(去重)", "mark(标色)"])
        self.cmb_dedupe.setCurrentIndex(0)
        opt_row.addWidget(self.cmb_dedupe)

        opt_row.addWidget(QLabel("输出目录:", InvoiceDialog))

        self.edit_outdir = QLineEdit(InvoiceDialog)
        self.edit_outdir.setObjectName("edit_outdir")
        self.edit_outdir.setPlaceholderText("选择或输入输出目录")
        opt_row.addWidget(self.edit_outdir)

        self.btn_browse = QPushButton("浏览", InvoiceDialog)
        self.btn_browse.setObjectName("btn_browse")
        opt_row.addWidget(self.btn_browse)

        opt_row.addStretch(1)
        layout.addLayout(opt_row)

        # ---- 操作按钮行 ----
        btn_row = QHBoxLayout()
        btn_row.setObjectName("horizontalLayout_buttons")

        self.btn_parse = QPushButton("开始解析", InvoiceDialog)
        self.btn_parse.setObjectName("btn_parse")
        btn_row.addWidget(self.btn_parse)

        self.btn_export = QPushButton("导出", InvoiceDialog)
        self.btn_export.setObjectName("btn_export")
        self.btn_export.setEnabled(False)
        btn_row.addWidget(self.btn_export)

        btn_row.addStretch(1)

        self.lbl_status = QLabel("就绪", InvoiceDialog)
        self.lbl_status.setObjectName("lbl_status")
        btn_row.addWidget(self.lbl_status)

        layout.addLayout(btn_row)

        # ---- 结果表格 ----
        self.table = QTableWidget(0, len(HEADERS), InvoiceDialog)
        self.table.setObjectName("table")
        self.table.setHorizontalHeaderLabels(HEADERS)
        self.table.horizontalHeader().setSectionResizeMode(QHeaderView.ResizeMode.Stretch)
        layout.addWidget(self.table, stretch=1)
